"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[663],{3855:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Designing for Active Lifestyles","href":"/case-studies/docs/designing-for-active-lifestyles","docId":"designing-for-active-lifestyles","unlisted":false},{"type":"link","label":"Unintentional Good","href":"/case-studies/docs/unintentional-good","docId":"unintentional-good","unlisted":false},{"type":"link","label":"Accessing Healthcare","href":"/case-studies/docs/accessing-healthcare","docId":"accessing-healthcare","unlisted":false},{"type":"link","label":"Unlocking lifelong learing","href":"/case-studies/docs/unlocking-lifelong-learing","docId":"unlocking-lifelong-learing","unlisted":false},{"type":"link","label":"Preserving the Past","href":"/case-studies/docs/preserving-the-past","docId":"preserving-the-past","unlisted":false},{"type":"link","label":"Harmonious Ties: Connection Through Music","href":"/case-studies/docs/harmonious-ties-connection-through-music","docId":"harmonious-ties-connection-through-music","unlisted":false},{"type":"link","label":"Threads & Trends","href":"/case-studies/docs/threads-trends","docId":"threads-trends","unlisted":false},{"type":"link","label":"Transportation and Mobility","href":"/case-studies/docs/transportation-and-mobility","docId":"transportation-and-mobility","unlisted":false},{"type":"link","label":"Becoming Iron-Man","href":"/case-studies/docs/becoming-iron-man","docId":"becoming-iron-man","unlisted":false},{"type":"link","label":"Simplify Your Life: Inspiring Productivity and Efficiency","href":"/case-studies/docs/simplify-your-life-inspiring-productivity-and-efficiency","docId":"simplify-your-life-inspiring-productivity-and-efficiency","unlisted":false},{"type":"link","label":"Art and Digital Media","href":"/case-studies/docs/art-and-digital-media","docId":"art-and-digital-media","unlisted":false},{"type":"link","label":"The Virtual Learnscape: AR/VR x Education","href":"/case-studies/docs/the-virtual-learnscape-ar-vr-x-education","docId":"the-virtual-learnscape-ar-vr-x-education","unlisted":false},{"type":"link","label":"Systemic Justice and Equity","href":"/case-studies/docs/systemic-justice-and-equity","docId":"systemic-justice-and-equity","unlisted":false},{"type":"link","label":"Hybrid Collaboration","href":"/case-studies/docs/hybrid-collaboration","docId":"hybrid-collaboration","unlisted":false},{"type":"link","label":"The Future of Philanthropy and Volunteering","href":"/case-studies/docs/the-future-of-philanthropy-and-volunteering","docId":"the-future-of-philanthropy-and-volunteering","unlisted":false},{"type":"link","label":"Accessible Design for Different Abilities","href":"/case-studies/docs/accessible-design-for-different-abilities","docId":"accessible-design-for-different-abilities","unlisted":false},{"type":"link","label":"Caring From Within","href":"/case-studies/docs/caring-from-within","docId":"caring-from-within","unlisted":false},{"type":"link","label":"Easing Life Transitions","href":"/case-studies/docs/easing-life-transitions","docId":"easing-life-transitions","unlisted":false},{"type":"link","label":"Education Technology","href":"/case-studies/docs/education-technology","docId":"education-technology","unlisted":false},{"type":"link","label":"Digital Wellbeing","href":"/case-studies/docs/digital-wellbeing","docId":"digital-wellbeing","unlisted":false},{"type":"link","label":"Multimodal Interfaces to Broaden Access","href":"/case-studies/docs/multimodal-interfaces-to-broaden-access","docId":"multimodal-interfaces-to-broaden-access","unlisted":false},{"type":"link","label":"Financial Literacy, Health and Resilience","href":"/case-studies/docs/financial-literacy-health-and-resilience","docId":"financial-literacy-health-and-resilience","unlisted":false},{"type":"link","label":"Engagement in Digital/Physical Space","href":"/case-studies/docs/engagement-in-digital-physical-space","docId":"engagement-in-digital-physical-space","unlisted":false},{"type":"link","label":"Health and Wellness","href":"/case-studies/docs/health-and-wellness","docId":"health-and-wellness","unlisted":false},{"type":"link","label":"Sustainability","href":"/case-studies/docs/sustainability","docId":"sustainability","unlisted":false},{"type":"link","label":"Arts and Culture","href":"/case-studies/docs/arts-and-culture","docId":"arts-and-culture","unlisted":false},{"type":"link","label":"Information Overload","href":"/case-studies/docs/information-overload","docId":"information-overload","unlisted":false},{"type":"link","label":"Assistive Technologies and Accessibility","href":"/case-studies/docs/assistive-technologies-and-accessibility","docId":"assistive-technologies-and-accessibility","unlisted":false},{"type":"link","label":"Educational Technology","href":"/case-studies/docs/educational-technology","docId":"educational-technology","unlisted":false},{"type":"link","label":"Digital Democracy","href":"/case-studies/docs/digital-democracy","docId":"digital-democracy","unlisted":false},{"type":"link","label":"Online/Local Community","href":"/case-studies/docs/online-local-community","docId":"online-local-community","unlisted":false},{"type":"link","label":"Health and Wellness","href":"/case-studies/docs/health-and-wellness-1","docId":"health-and-wellness-1","unlisted":false}]},"docs":{"accessible-design-for-different-abilities":{"id":"accessible-design-for-different-abilities","title":"Accessible Design for Different Abilities","description":"Disability is a \u201cmismatched interaction between the features of a person\u2019s body and the features of the environment in which they live\u201d (World Health Organization, 2011). In this studio, we will address this mismatch through multimodal interfaces, inclusive design thinking practices, and the implementation of accessible features to create products that are better for everyone. Together, we will explore how to build a world that better supports people such as neurodivergent students who are learning online, blind users who navigate technology with screen readers, or elders with limited mobility who are living independently.","sidebar":"tutorialSidebar"},"accessing-healthcare":{"id":"accessing-healthcare","title":"Accessing Healthcare","description":"The COVID-19 pandemic revealed just how fractured our healthcare system is, providing healthcare that is not equitable nor accessible to all. The supreme court overturning Roe v. Wade has had major consequences for peoples\u2019 access to reproductive healthcare and has raised concerns about data privacy in personal health apps. Due to increased demand for OBGYN care, patients must often wait months for care at a women\'s health clinic.","sidebar":"tutorialSidebar"},"art-and-digital-media":{"id":"art-and-digital-media","title":"Art and Digital Media","description":"Art encourages self-expression, creativity, and social change, and the rise of digital culture transforms how we share ideas and aesthetic experiences that resonate with us and our communities. Our fluid digital media ecosystem offers new forms of interaction across traditional and hybrid art forms (e.g., food, games, journalism, literature, music, and visual arts) using a variety of technologies (e.g., artificial intelligence, video streaming, social media, and virtual reality). How might we (re)shape the perspectives and power of content creators, curators, and consumers, increase engagement with cultural centers, and expand our understanding of our real and imagined worlds?","sidebar":"tutorialSidebar"},"arts-and-culture":{"id":"arts-and-culture","title":"Arts and Culture","description":"Art and culture are integral to a vibrant community, illuminating our inner selves and expanding our worldview through common values and shared experiences. In this studio, we will explore arts and culture from the lenses of the creator, curator, and consumer across a medium of your choice (e.g. visual arts, design, music, performance). We will investigate using design and technology to help creators execute on their creativity and enable people to discover content which they resonate with.","sidebar":"tutorialSidebar"},"assistive-technologies-and-accessibility":{"id":"assistive-technologies-and-accessibility","title":"Assistive Technologies and Accessibility","description":"There are many opportunities for technology to improve the lives of people with special needs. However, these communities are often underserved due to lack of awareness and failure to incorporate accessibility features into applications designed for the general public. In this studio we will explore how the intersection of design, technology, and accessibility can create a positive impact in special needs communities","sidebar":"tutorialSidebar"},"becoming-iron-man":{"id":"becoming-iron-man","title":"Becoming Iron-Man","description":"With the help of assistive technology, we can do almost anything. Want to know","sidebar":"tutorialSidebar"},"caring-from-within":{"id":"caring-from-within","title":"Caring From Within","description":"Especially considering the pandemic triggering a worldwide mental health crisis, users are increasingly using their devices to manage their mental wellbeing. In this studio, we will explore the intersection of technology and health to help us better manage, improve, and care for our own mental health and those around us. With the rapidly growing interest in this field and thus abundant opportunities for innovation, how might we extend help to users and empower them to care for themselves from within?","sidebar":"tutorialSidebar"},"designing-for-active-lifestyles":{"id":"designing-for-active-lifestyles","title":"Designing for Active Lifestyles","description":"Physical activity is fundamental to health, reducing the risk of many chronic diseases. However, many in the US and globally fall short of meeting physical activity guidelines. People face many unique barriers to physical activity, such as physical limitations, geographic and environmental constraints, lack of resources or income, social pressures, fixed mindsets, and health beliefs, and more. Many existing health tools embrace a \u201cone-size-fits-all\u201d approach, assuming standard graphs and statistics will work for everyone. In this studio, we\'ll explore tools to address these unique barriers. How can we promote physical activity across demographics and abilities? How do we foster long-term, sustainable habits? And how do we bridge geographic and economic gaps in access to exercise?","sidebar":"tutorialSidebar"},"digital-democracy":{"id":"digital-democracy","title":"Digital Democracy","description":"For a democracy to flourish, citizens need to be well-informed to meaningfully engage with each other and the larger public sphere. Though much of this occurs online today, the outcomes are still manifest in real-world political, social, and economic institutions. In this studio, we will build novel and ethical design solutions bridging technology and the public sphere. How might we leverage technological tools to enrich online knowledge-sharing, debate, trust, and participation? How can we present complex information to voters in clear and relevant ways? How can we design platforms to reach beyond cyberspace and encourage real-world organizing and voting?","sidebar":"tutorialSidebar"},"digital-wellbeing":{"id":"digital-wellbeing","title":"Digital Wellbeing","description":"Especially during the pandemic, we spend much of our day staring at a screen. All the digital activities we engage in affect our behavior and our mental and physical health. Screen addiction is real, but not totally inevitable! There are lots of unique approaches to mitigating the harms of our digital lives. In this studio we will explore topics such as social comparison and doom scrolling and discover ways to build digital experiences that work with you, not against you.","sidebar":"tutorialSidebar"},"easing-life-transitions":{"id":"easing-life-transitions","title":"Easing Life Transitions","description":"As we go through life, big transitions from one stage to another can be accompanied with feelings of discomfort and big personal growth. Whether you are moving out of home for the first time, becoming a new parent, starting your first job, or retiring, these life transitions change the fabric of your life. How can we design solutions for people going through life transitions to increase self-fulfillment, ease fears, and encourage growth? How can we help people in life transitions learn the information necessary to enter a new phase of life with confidence?","sidebar":"tutorialSidebar"},"education-technology":{"id":"education-technology","title":"Education Technology","description":"Technology is becoming more present in the education process from devices in the classroom to parents communicating with teachers. In this studio we will look at educational technology, and how this technology fits in the education ecosystem. We will look for ways that you can use careful design and technology to enhance traditional learning experiences or create new opportunities for learning that haven\u2019t been possible before.","sidebar":"tutorialSidebar"},"educational-technology":{"id":"educational-technology","title":"Educational Technology","description":"Technology is becoming more present in the education process from devices in the classroom to parents communicating with teachers. In this studio we will look at educational technology, and how this technology fits in the education ecosystem. We will look for ways that you can use careful design and technology to enhance traditional learning experiences or create new opportunities for learning that haven\'t been possible before.","sidebar":"tutorialSidebar"},"engagement-in-digital-physical-space":{"id":"engagement-in-digital-physical-space","title":"Engagement in Digital/Physical Space","description":"Now more than ever online communities are blooming, but to engage with others in digital space we often must disengage from our own physical experiences. How might we bridge the gap between the digital and physical worlds? How might we engage and connect more deeply with the real world through the power of technology?","sidebar":"tutorialSidebar"},"financial-literacy-health-and-resilience":{"id":"financial-literacy-health-and-resilience","title":"Financial Literacy, Health and Resilience","description":"Financial health (personal and business) has a huge impact on reducing poverty, the gender gap and wealth inequality. Existing financial products do not meet the needs of financially underserved individuals or businesses. In addition, most financial products are neither affordable nor accessible to these groups and this impacts the health of local economies. This studio will explore how technology can help increase financial health and resiliency for both individuals and small businesses thus better addressing financial needs in the 21st century","sidebar":"tutorialSidebar"},"harmonious-ties-connection-through-music":{"id":"harmonious-ties-connection-through-music","title":"Harmonious Ties: Connection Through Music","description":"To me, music has always been the lifeblood of human connection; it presents a shared language that allows us to communicate in a unique way. So how is it that, as the music world grows bigger and widens our domain for potential connection, meaningful music-based connections seem to be harder to attain?","sidebar":"tutorialSidebar"},"health-and-wellness":{"id":"health-and-wellness","title":"Health and Wellness","description":"Digital health is one of the most important and fastest growing industries, especially given the new necessity of remote care. In this studio, we will explore how the intersection of health and technology can help us better understand our health and take proactive action. This area is filled with opportunities for innovation like smart devices that monitor and improve our health, solutions that enable more accessible and effective healthcare, and products that enhance our physical or mental wellbeing.","sidebar":"tutorialSidebar"},"health-and-wellness-1":{"id":"health-and-wellness-1","title":"Health and Wellness","description":"Our current healthcare system is centered around reactive responses to ailment and disease. Through our studio, we will explore how the intersection of health and technology can help us provide a","sidebar":"tutorialSidebar"},"hybrid-collaboration":{"id":"hybrid-collaboration","title":"Hybrid Collaboration","description":"With the rising popularity of remote work, we are seeing an exponential increase in the need for hybrid collaboration (e.g., face-to-face and online, synchronous and asynchronous, etc.). Based on the requirements of our work, we select, combine, and make the best of different modes to achieve the optimal collaborative experience and group outcome. How might we improve group engagement and success by working with both tangible and digital materials? How might we bridge the gaps between different digital and physical collaboration methods? In this studio, we will explore and propose novel designs for hybrid collaboration experiences.","sidebar":"tutorialSidebar"},"information-overload":{"id":"information-overload","title":"Information Overload","description":"Although living in the Digital Age has its perks, having access to so much information and content online can feel confusing, distracting, overwhelming, or even paralyzing. Information overload is the difficulty in understanding an issue and effectively making decisions due to too much data. This studio seeks to understand the mental & emotional burdens related to digital media and help humans regain control over their content consumption.","sidebar":"tutorialSidebar"},"multimodal-interfaces-to-broaden-access":{"id":"multimodal-interfaces-to-broaden-access","title":"Multimodal Interfaces to Broaden Access","description":"Information seeking has become, for many people, an indispensable part of modern life, yet it always presents significant challenges for users with special needs, such as elders, blind or visually impaired users, or children. Could there be a better multi-modal system to facilitate users with special needs in the online information acquisition process? In this studio, we will explore approaches such as voice-interaction, mobile phone assistants, human-environment interaction, as well as how these could work together to better create a positive impact in the special needs communities.","sidebar":"tutorialSidebar"},"online-local-community":{"id":"online-local-community","title":"Online/Local Community","description":"Digital communities continue to appear and we\'re spending more time online than offline. While online communities are blooming, we tend to overlook the community that exists outside the digital realm. How might we bridge the gap between the digital world and the real world? How might we engage more with the real world through the power of technology?","sidebar":"tutorialSidebar"},"preserving-the-past":{"id":"preserving-the-past","title":"Preserving the Past","description":"New technologies allow us to preserve history more easily than ever. We can record our family\u2019s stories for future generations to see and hear, snap pictures and share the memories with others, even visit historical sites without leaving our homes. In this studio, we will explore ways to capture and revive the past. How can we leverage digital capabilities to preserve and cherish our histories? How can we save our memories and cultures so they endure?","sidebar":"tutorialSidebar"},"simplify-your-life-inspiring-productivity-and-efficiency":{"id":"simplify-your-life-inspiring-productivity-and-efficiency","title":"Simplify Your Life: Inspiring Productivity and Efficiency","description":"Technology continues to play an integral role in our daily lives. Some important practical and productive features can be muddled by the constant stream of extraneous information and distractions. As we step away from our phones, we are still bombarded with high amounts of sensory information, busy schedules, and endless to-dos to check off our lists. Even small tasks may inadvertently lead to a high energy expenditure if the path to completion is overly complicated. Amidst all of the chaos, it is important to find ways to offload the high volume of information. How might we avoid the feeling of fatigue and instead explore technology that inspires focus, personal growth, and efficiency? In this studio, we will be exploring topics in behavior change and productivity to create supportive technology that operates as a personal assistant or life coach.","sidebar":"tutorialSidebar"},"sustainability":{"id":"sustainability","title":"Sustainability","description":"Sustainability is a mounting global challenge, with environmental health being inextricably linked to human health. How can technology help individuals and communities engage in more sustainable living? In this studio, we will explore local and global efforts to promote the health of the environment, with an eye towards maintaining a habitable planet for future generations. We will look into applications of design and technology within sustainability, such as creating eco-friendly living spaces, reducing food waste, and promoting ethical consumerism.","sidebar":"tutorialSidebar"},"systemic-justice-and-equity":{"id":"systemic-justice-and-equity","title":"Systemic Justice and Equity","description":"Extreme wealth inequality is intertwined with systemic injustice (in the form of race, gender, ethnicity, class, etc.) and can have crippling consequences in countries where wealth is necessary for access to essentials like food, shelter, healthcare, education, and legal services. This studio will examine gaps in the social security system for those living in poverty and/or facing systemic injustice. We will find tech solutions to tackle systemic issues or lessen negative outcomes for those in a harmful system, with the aim of creating an equal opportunity society. Our studio will stay cognizant of tech as a potential contributor to systemic injustice and of the potential minimization of serious issues inherent in creating a project within 10 weeks.","sidebar":"tutorialSidebar"},"the-future-of-philanthropy-and-volunteering":{"id":"the-future-of-philanthropy-and-volunteering","title":"The Future of Philanthropy and Volunteering","description":"With a growing population of millennials and Gen Z adults as well as the dawn of the centimillionaire, we\u2019re seeing signs of a changing philanthropy and volunteering landscape. Organic and creative new methods of donorship, such as bingo donation games on Instagram Stories, display how times are changing and there\u2019s room for innovation. How might we reinvent philanthropy in the 21st century?","sidebar":"tutorialSidebar"},"the-virtual-learnscape-ar-vr-x-education":{"id":"the-virtual-learnscape-ar-vr-x-education","title":"The Virtual Learnscape: AR/VR x Education","description":"Augmented and virtual reality technologies can unlock unique, immersive learning experiences. Use AR to learn about a new animal by placing it in the room with you. Travel across space and time to gain a deeper understanding of a different society. Simulate high-risk surgeries in a low risk setting to perfect skills. AR/VR innovation in education technology has started to serve the needs of a range of learners from the casually curious to k-12 students to medical professionals \u2013 but it has just scratched the surface of its potential. In this studio, we will explore how we might design game-changing AR/VR educational experiences.","sidebar":"tutorialSidebar"},"threads-trends":{"id":"threads-trends","title":"Threads & Trends","description":"Many people have benefited from active digital spaces that hold tons of crowdsourced knowledge. From trying to answer burning questions to having deep philosophical discussions to sharing memes, people have different motivations for participating in these online communities. What design decisions help keep these communities flourishing and alive? How can information be connected to those who need it? How can users be incentivized to share knowledge with others? In this studio, students explore how different communities within a domain could benefit from knowledge sharing.","sidebar":"tutorialSidebar"},"transportation-and-mobility":{"id":"transportation-and-mobility","title":"Transportation and Mobility","description":"Technology is fundamentally reinventing the way we move from Point A to Point B. From ride-sharing to car system control applications (think Tesla) to smart navigation, mobility and transportation in the 21st century are constantly challenging and evolving our perceptions of movement. How might we continue to reinvent travel and transport as technology evolves?","sidebar":"tutorialSidebar"},"unintentional-good":{"id":"unintentional-good","title":"Unintentional Good","description":"Balancing financial wellness, social responsibilities, and environmental conservation is a goal many strive for. Yet, convenience often takes precedence over these objectives.","sidebar":"tutorialSidebar"},"unlocking-lifelong-learing":{"id":"unlocking-lifelong-learing","title":"Unlocking lifelong learing","description":"In a world changing faster than ever, lifelong learning is not just a","sidebar":"tutorialSidebar"}}}}')}}]);